-- PLAN FLIP SUMMARY:
-- QP1 → QP2 flip: 500 students / 2,000 enrollments
--                 (Nested Loop → Hash Match)
-- QP2 → QP3 flip: 5,000 students / 30,000 enrollments
--                 (Hash Match → Merge Join)
-- QP3 → QP4 flip: 30,000 students / 400,000 enrollments
--                 (Merge Join → Parallel Plan)
-- QP4 → QP5 flip: 50,000 students / 680,000 enrollments
--                 (Parallel → Parallel + Missing Index warning)
--
-- 5x5 MATRIX SUMMARY (subtree cost):
--              QP1      QP2     QP3     QP4     QP5
-- S1 (5/8)    0.023*   0.111   0.128   0.261   0.261
-- S2 (500/2k) 0.723    0.227*  0.237   0.298   0.298
-- S3 (5k/30k) 12.063   3.185   1.460*  0.744   0.744
-- S4 (30k/400k)166.611 44.718  15.004  5.607*  5.607
-- S5 (50k/680k)285.828 78.309  25.408  9.334   9.334*
-- (* = natural optimizer choice)
-- =============================================



-- STAGE 1: Create database and tables 
-- Linda_Q0_Projects 

-- change current working database to the system databse "master"
-- use mast because it cannot dropw a databse while using it
USE master
GO

-- Check if a database named Linda_QO_Projects already exsists
IF EXISTS (SELECT name 
           FROM sys.databases 
           WHERE name = 'Linda_QO_Project2')
    -- delete the old database completely if it exists, this give a fresh clean datbase every time
    DROP DATABASE Linda_QO_Project2
GO

-- Create a brand new database named Linda_Q0_Project2
CREATE DATABASE Linda_QO_Project2
GO

-- Switch current working database to Linda_Q0_Project2
-- all tables and objects ofter this line will be created inside this database
USE Linda_QO_Project2
GO
--SELECT COUNT(*) AS StudentCount FROM Students
--SELECT COUNT(*) AS ClassCount FROM Classes
--SELECT COUNT(*) AS EnrollmentCount FROM Enrollments

--SELECT COUNT(*) AS Students FROM Students
--SELECT COUNT(*) AS Enrollments FROM Enrollments

 --SELECT name AS TableName FROM sys.tables ORDER BY name -- with above line fro check all 3 tables exist.

UPDATE STATISTICS Students
UPDATE STATISTICS Enrollments
UPDATE STATISTICS Classes
GO
-- Table 1: students

-- Create table names Students
CREATE TABLE Students(
    
    -- studentID, unique number for each student; INT = interger number; NOT NULL = value is requied
    StudentID INT NOT NULL,
    
    -- studentName, store student full name; NVARCHR supports unicoe text; up to 100 characters
    StudentName NVARCHAR(100),

    -- Age, store student age.
    Age INT,

    -- address: city, stores students city
    City NVARCHAR(50)
)
GO

-- TABLE 2: classes

-- create table named classes
CREATE TABLE Classes
(
    --classID, unique ID for each class
    ClassID INT NOT NULL,

    --className, store class/course systems
    ClassName NVARCHAR(100),

    --Semester: stores acdemic Semester
    Semester NVARCHAR(30)
)
GO

-- TABLE 3: Enrollments

--create table named enrollments, the table connects students and classes(like a bridge/ junction table)
CREATE TABLE Enrollments(
    --enrollmentID: unique ID for each enrollment record
    EnrollmentID INT NOT NULL,

    --StudnetID, refers to a student in students table
    StudentID INT,

    --classID: refers to a class is classes table
    ClassID INT,

    -- grade: store final grade (A,B+,C)
    Grade NVARCHAR(5)
)
GO

-- ADD PRIMARY KEYS

--Add primary key to students table 
-- sql server automatically create clustered index
ALTER TABLE Students
    -- PK_Students = constraint name
    ADD CONSTRAINT PK_Students
    PRIMARY KEY (StudentID)

    -- Add primary key to classes table 
ALTER TABLE Classes
    ADD CONSTRAINT PK_Classes
    PRIMARY KEY (ClassID)
GO

-- add primary key to enrollment table 
ALTER TABLE Enrollments 
    ADD CONSTRAINT PK_Enrollments
    PRIMARY KEY (EnrollmentID)

-- ADD FOREIGN KEYS 

--foreign key connect enrollments.studentID 
-- to students.StudentID
-- this enforce relationship integrity, cannnot enroll a student that does not exist

ALTER TABLE Enrollments

    ADD CONSTRAINT FK_Enrollments_Students
    FOREIGN KEY (StudentID)
    
    REFERENCES Students(StudentID)
-- Foreign key connects Enrollments.ClassID
-- to Classes.ClassID

-- cannot enroll into a class that does not exist
ALTER TABLE Enrollments

    ADD CONSTRAINT FK_Enrollments_classes
    FOREIGN KEY (ClassID)

    REFERENCES Classes(ClassID) -- REFERENCES = verify/check existence(QC)
GO

-- CREATEE NONCLUSTERED INDEXES

--Create index on Students.City, helps saerching / filtering by city
--i.g.: SELECT * FROM Students WHERE City = 'Seattle'
CREATE NONCLUSTERED INDEX IX_Students_City

    ON Students (City)

-- Create index on Enrollments.StudentID, helps JOIN operations between students and enrollments
CREATE NONCLUSTERED INDEX IN_Enrollments_StudentsID
    ON Enrollments(StudentID)

-- Create index on Enrollments.ClassID, helps JOIN operations between classes and enrollments
CREATE NONCLUSTERED INDEX IX_Enrollments_ClassID
    ON Enrollments(ClassID)
GO


