INSERT INTO Enrollments VALUES (2, 1, 2, 'B+')
INSERT INTO Enrollments VALUES (3, 2, 1, 'B')
INSERT INTO Enrollments VALUES (4, 3, 1, 'A')
INSERT INTO Enrollments VALUES (5, 3, 3, 'B+')
INSERT INTO Enrollments VALUES (6, 4, 2, 'A')
INSERT INTO Enrollments VALUES (7, 5, 1, 'A')
INSERT INTO Enrollments VALUES (8, 5, 3, 'C')
