-- SELECT = choose which columns to display in output
SELECT 
    -- get studentName column from students table 
    -- "s" is alias name for students
    s.StudentName,

    -- get classname column from classes table 
    -- 'c' is alias name for classes
    c.ClassName,

    -- get semester column from classes table 
    c.Semester,


    -- count number of enrollments
    COUNT(e.EnrollmentID) AS TotalEnrollments

-- start from students table
-- s = alias (short name for students)
FROM Students s
-- join enrollments e
JOIN Enrollments e

    -- match same studentID, connect student with enrollment record
    ON s.StudentID = e.StudentID

-- join classes table
JOIN Classes c

    -- Match same ClassID, conncet enrollment with class
    ON e.ClassID = c.ClassID

-- filter only seattle students
WHERE s.City = 'Seattle'

-- group rows beofore counting( group by student, class, semester
GROUP BY  s.StudentName,c.ClassName, c.Semester
   

-- SITUATION 2: ADD MORE STUDENTS AND ENROLLMENTS
-- TARGET: slowly riase up table size, then observe when SQL server changes execution plan(flit point)

-- create an integer variable named @i
-- start value = 6, because 6 student IDs 1-5 likely already exist on table 

DECLARE @i INT = 6

-- WHILE LOOP: keep repeating as long as @i <= 50
-- meaning: add students from ID 6-50
WHILE @i <= 50
-- BEGIN = start block, END = end block
BEGIN
    -- Insert one row into students table
    INSERT INTO Students

    -- VALUES order must table column order
    VALUES
    (
    -- studentID: i.g. 6,7,8...
    -- studentName; create dynamic name; 'Student_6' 'Student_7'
    @i,
    -- CAST convert number into text
    'Student_' + CAST(@i AS NVARCHAR),
    -- age, eery student age = 20
    20,
    --city, every student lives in Seattle
    'Seattle'
    )
    
    -- increase @i by 1
    SET @i = @i+1
END
GO

-- ADD more enrollment rows

-- create integer varibale @j, start at enrollmentID = 9, why 9? because  1-8 may already exist
DECLARE @j INT = 9

    -- repleat loop while @j <= 100; add enrollment records form ID 9 -100
WHILE @j <= 100
BEGIN

    -- insert one row into enrollments table 
    INSERT INTO Enrollments
    VALUES
    (
        @j,
        -- studentID, % = modulus for find remainder (@j % 5) gives 0,1,2,3,4 repeating
        -- +1 change it to: 1,2,3,4,5, repeating; goal: reuse StudentID values, instead of createing random invalid IDS
        (@j % 5) + 1,

        -- classID save work process like above 
        (@j % 3) + 1,
        -- grade, everone gets grade B
        'B'
        
    )

    -- increase @j by 1; example 9->10->11
    SET @j = @j+1
END
GO

-- Situation 3: add many more rows to force plan change
DECLARE @i INT = 51
WHILE @i <= 500
BEGIN
    INSERT INTO Students VALUES (@i, 'Student_' + CAST(@i AS NVARCHAR), 20, 'Seattle')
    SET @i = @i + 1
END
GO

DECLARE @j INT = 101
WHILE @j <= 2000
BEGIN
    INSERT INTO Enrollments VALUES (@j, (@j % 50) + 1, (@j % 3) + 1, 'B')
    SET @j = @j + 1
END
GO

-- Finding QP3: add more rows to trigger next plan flip
DECLARE @i INT = 501
WHILE @i <= 2000
BEGIN
    INSERT INTO Students VALUES (@i, 'Student_' + CAST(@i AS NVARCHAR), 20, 'Seattle')
    SET @i = @i + 1
END
GO

DECLARE @j INT = 2001
WHILE @j <= 10000
BEGIN
    INSERT INTO Enrollments VALUES (@j, (@j % 500) + 1, (@j % 3) + 1, 'B')
    SET @j = @j + 1
END
GO


-- Adding more rows to find QP3 flip point
DECLARE @i INT = 2001
WHILE @i <= 5000
BEGIN
    INSERT INTO Students VALUES (@i, 'Student_' + CAST(@i AS NVARCHAR), 20, 'Seattle')
    SET @i = @i + 1
END
GO

DECLARE @j INT = 10001
WHILE @j <= 30000
BEGIN
    INSERT INTO Enrollments VALUES (@j, (@j % 2000) + 1, (@j % 3) + 1, 'B')
    SET @j = @j + 1
END
GO
    

-- Add more classes to force Merge Join consideration
DECLARE @k INT = 4
WHILE @k <= 500
BEGIN
    INSERT INTO Classes VALUES (@k, 'Class_' + CAST(@k AS NVARCHAR), 'Spring 2026')
    SET @k = @k + 1
END
GO

-- Finding QP4: add more rows
DECLARE @i INT = 10001
WHILE @i <= 20000
BEGIN
    INSERT INTO Students VALUES (@i, 'Student_' + CAST(@i AS NVARCHAR), 20, 'Seattle')
    SET @i = @i + 1
END
GO

DECLARE @j INT = 80001
WHILE @j <= 200000
BEGIN
    INSERT INTO Enrollments VALUES (@j, (@j % 10000) + 1, (@j % 3) + 1, 'B')
    SET @j = @j + 1
END
GO

-- Finding QP4: adding even more rows
DECLARE @i INT = 20001
WHILE @i <= 30000
BEGIN
    INSERT INTO Students VALUES (@i, 'Student_' + CAST(@i AS NVARCHAR), 20, 'Seattle')
    SET @i = @i + 1
END
GO

DECLARE @j INT = 200001
WHILE @j <= 400000
BEGIN
    INSERT INTO Enrollments VALUES (@j, (@j % 20000) + 1, (@j % 3) + 1, 'B')
    SET @j = @j + 1
END
GO

-- Finding QP5: add more rows for final plan flip
DECLARE @i INT = 30001
WHILE @i <= 50000
BEGIN
    INSERT INTO Students VALUES (@i, 'Student_' + CAST(@i AS NVARCHAR), 20, 'Seattle')
    SET @i = @i + 1
END
GO

DECLARE @j INT = 400001
WHILE @j <= 800000
BEGIN
    INSERT INTO Enrollments VALUES (@j, (@j % 30000) + 1, (@j % 3) + 1, 'B')
    SET @j = @j + 1
END
GO

