-- INITIAL APPROACH: Using join hints (LOOP JOIN, HASH JOIN, MERGE JOIN)
-- Note: These were exploratory measurements before switching to XML plan forcing
-- The XML-based measurements below are the final values used in the 5x5 matrix

-- MATRIX: Situation 1 data, Force each join type
-- Ctrl+M ON

-- Force QP1 style (Loop Join)
SELECT 
    s.StudentName, c.ClassName, c.Semester,
    COUNT(e.EnrollmentID) AS TotalEnrollments
FROM Students s
JOIN Enrollments e ON s.StudentID = e.StudentID
JOIN Classes c ON e.ClassID = c.ClassID
WHERE s.City = 'Seattle'
GROUP BY s.StudentName, c.ClassName, c.Semester
OPTION (LOOP JOIN)
GO

-- MATRIX: Situation 1 data, Force QP2 style (Hash Join)
SELECT 
    s.StudentName, c.ClassName, c.Semester,
    COUNT(e.EnrollmentID) AS TotalEnrollments
FROM Students s
JOIN Enrollments e ON s.StudentID = e.StudentID
JOIN Classes c ON e.ClassID = c.ClassID
WHERE s.City = 'Seattle'
GROUP BY s.StudentName, c.ClassName, c.Semester
OPTION (HASH JOIN)
GO

-- MATRIX: Situation 1 data, Force QP3 style (Merge Join)
SELECT 
    s.StudentName, c.ClassName, c.Semester,
    COUNT(e.EnrollmentID) AS TotalEnrollments
FROM Students s
JOIN Enrollments e ON s.StudentID = e.StudentID
JOIN Classes c ON e.ClassID = c.ClassID
WHERE s.City = 'Seattle'
GROUP BY s.StudentName, c.ClassName, c.Semester
OPTION (MERGE JOIN)
GO

-- MATRIX: Situation 1 data, Force QP4 style (Hash Join + Parallelism)
SELECT 
    s.StudentName, c.ClassName, c.Semester,
    COUNT(e.EnrollmentID) AS TotalEnrollments
FROM Students s
JOIN Enrollments e ON s.StudentID = e.StudentID
JOIN Classes c ON e.ClassID = c.ClassID
WHERE s.City = 'Seattle'
GROUP BY s.StudentName, c.ClassName, c.Semester
OPTION (HASH JOIN, NO_PERFORMANCE_SPOOL)
GO

-- MATRIX: Situation 1 data, Force QP5 style (Loop Join + Max Parallelism)
SELECT 
    s.StudentName, c.ClassName, c.Semester,
    COUNT(e.EnrollmentID) AS TotalEnrollments
FROM Students s
JOIN Enrollments e ON s.StudentID = e.StudentID
JOIN Classes c ON e.ClassID = c.ClassID
WHERE s.City = 'Seattle'
GROUP BY s.StudentName, c.ClassName, c.Semester
OPTION (LOOP JOIN, MAXDOP 6)
GO

