-- MATRIX: Situation 2 data, Force QP4 via XML plan
SELECT 
    s.StudentName, c.ClassName, c.Semester,
    COUNT(e.EnrollmentID) AS TotalEnrollments
FROM Students s
JOIN Enrollments e ON s.StudentID = e.StudentID
JOIN Classes c ON e.ClassID = c.ClassID
WHERE s.City = 'Seattle'
GROUP BY s.StudentName, c.ClassName, c.Semester
