-- MATRIX: Situation 2 data, Force QP5 via XML plan
SELECT 
    s.StudentName, c.ClassName, c.Semester,
    COUNT(e.EnrollmentID) AS TotalEnrollments
FROM Students s
JOIN Enrollments e ON s.StudentID = e.StudentID
JOIN Classes c ON e.ClassID = c.ClassID
WHERE s.City = 'Seattle'
GROUP BY s.StudentName, c.ClassName, c.Semester
OPTION (USE PLAN N'<?xml version="1.0" encoding="utf-16"?>
<ShowPlanXML xmlns:xsd="http://www.w3.org/2001/XMLSchema" xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance" Version="1.599" Build="17.0.1110.1" xmlns="http://schemas.microsoft.com/sqlserver/2004/07/showplan">
  <BatchSequence>
