-- Reset to Situation 4 data (30000 students, 400000 enrollments)
DELETE FROM Enrollments
DELETE FROM Students
GO

DECLARE @i INT = 1
WHILE @i <= 30000
BEGIN
    INSERT INTO Students VALUES (@i, 'Student_' + CAST(@i AS NVARCHAR), 20, 'Seattle')
    SET @i = @i + 1
END
GO

DECLARE @j INT = 1
WHILE @j <= 400000
BEGIN
    INSERT INTO Enrollments VALUES (@j, (@j % 30000) + 1, (@j % 3) + 1, 'B')
    SET @j = @j + 1
END
GO

SELECT COUNT(*) AS Students FROM Students
SELECT COUNT(*) AS Enrollments FROM Enrollments
GO

-- MATRIX: Situation 4 data, Force QP1 via XML plan
-- Ctrl+M ON before running this
SELECT 
    s.StudentName,
    c.ClassName,
    c.Semester,
    COUNT(e.EnrollmentID) AS TotalEnrollments
FROM Students s
JOIN Enrollments e ON s.StudentID = e.StudentID
JOIN Classes c ON e.ClassID = c.ClassID
WHERE s.City = 'Seattle'
GROUP BY s.StudentName, c.ClassName, c.Semester
